using namespace std;
int main(){
    int N, M;
    cin >> N >> M;
    vector<int> nums;
    for(int i = 0; i < N; i++){
        int row_len;
        cin >> row_len;
        for(int j = 0; j < M; j++){
            int num;
            cin >> num;
            nums.push_back(num);
        }
    }
    sort(nums.begin(), nums.end());
    int length = nums.size();
    if(length % 2 == 1){
        cout << nums[length / 2] << endl;
    }else{
        cout << (nums[length / 2 - 1] + nums[length / 2]) / 2.0 << endl;
    }
}
